/**
 * A unique, non-enumerable key for the internal event map.
 * Using a Symbol prevents property name collisions on the consuming class instance,
 * providing a robust way to manage private state within a mixin.
 * @type {Symbol}
 */

examples:
listeners: {
    myEvent: 'onMyEvent',
    otherEvent: {
        fn: 'onOtherEvent',
        delay: 100,
        once: true
    },
    scope: this
}

